AND (
	(
		COALESCE(NULLIF(TRIM(rm.hospital_id), ''), '') = ''
		OR EXISTS (
			SELECT 1 FROM scm_hospital_user hu
			WHERE hu.user_id = #{userId}
			  AND (hu.del_flag = '0' OR hu.del_flag IS NULL)
			  AND CAST(hu.hospital_id AS CHAR) = TRIM(rm.hospital_id)
		)
	)
	AND (
		COALESCE(NULLIF(TRIM(rm.supplier_id), ''), '') = ''
		OR EXISTS (
			SELECT 1 FROM scm_supplier_user su
			WHERE su.user_id = #{userId}
			  AND (su.del_flag = '0' OR su.del_flag IS NULL)
			  AND CAST(su.supplier_id AS CHAR) = TRIM(rm.supplier_id)
		)
	)
)

AND (
	(
		COALESCE(NULLIF(TRIM(rm.hospital_id), ''), '') = ''
		OR EXISTS (
			SELECT 1 FROM scm_hospital_user hu
			WHERE hu.user_id = #{params.userId}
			  AND (hu.del_flag = '0' OR hu.del_flag IS NULL)
			  AND CAST(hu.hospital_id AS CHAR) = TRIM(rm.hospital_id)
		)
	)
	AND (
		COALESCE(NULLIF(TRIM(rm.supplier_id), ''), '') = ''
		OR EXISTS (
			SELECT 1 FROM scm_supplier_user su
			WHERE su.user_id = #{params.userId}
			  AND (su.del_flag = '0' OR su.del_flag IS NULL)
			  AND CAST(su.supplier_id AS CHAR) = TRIM(rm.supplier_id)
		)
	)
)

